// @ts-check
/// <reference types="@actions/github-script" />

/**
 * Generates a standalone workflow-id XML comment marker for searchability.
 * This marker enables finding all items (issues, discussions, PRs, comments)
 * generated by a specific workflow.
 *
 * @param {string} workflowId - Workflow identifier
 * @returns {string} Standalone workflow-id XML comment marker
 */
function generateWorkflowIdMarker(workflowId) {
  return `<!-- gh-aw-workflow-id: ${workflowId} -->`;
}

/**
 * Gets the workflow-id marker content (without XML comment wrapper) for searching.
 * This is used when searching for issues/discussions/PRs by workflow-id.
 *
 * @param {string} workflowId - Workflow identifier
 * @returns {string} Workflow-id marker content for search queries
 */
function getWorkflowIdMarkerContent(workflowId) {
  return `gh-aw-workflow-id: ${workflowId}`;
}

/**
 * Check if a comment body matches a workflow ID marker.
 * Supports standalone (<!-- gh-aw-workflow-id: value -->) and combined XML marker formats.
 * @param {string|null|undefined} body - Comment body
 * @param {string} workflowId - Workflow ID to match
 * @returns {boolean}
 */
function matchesWorkflowId(body, workflowId) {
  if (!body || body.includes(`<!-- gh-aw-comment-type: reaction -->`)) return false;
  if (body.includes(`<!-- gh-aw-workflow-id: ${workflowId} -->`)) return true;
  return body.includes(`<!-- gh-aw-agentic-workflow:`) && (body.includes(`workflow_id: ${workflowId},`) || body.includes(`workflow_id: ${workflowId} -->`));
}

/**
 * Generates an XML comment marker with agentic workflow metadata for traceability.
 * This marker enables searching and tracing back items generated by an agentic workflow.
 *
 * Note: This function is duplicated in messages_footer.cjs. While normally we would
 * consolidate to a shared module, importing messages_footer.cjs here would cause the
 * bundler to inline messages_core.cjs which contains 'GH_AW_SAFE_OUTPUT_MESSAGES:' in
 * a warning message, breaking tests that check for env var declarations.
 *
 * @param {string} workflowName - Name of the workflow
 * @param {string} runUrl - URL of the workflow run
 * @returns {string} XML comment marker with workflow metadata
 */
function generateXMLMarker(workflowName, runUrl) {
  // Read engine metadata from environment variables
  const engineId = process.env.GH_AW_ENGINE_ID || "";
  const engineVersion = process.env.GH_AW_ENGINE_VERSION || "";
  const engineModel = process.env.GH_AW_ENGINE_MODEL || "";
  const trackerId = process.env.GH_AW_TRACKER_ID || "";
  const runId = process.env.GITHUB_RUN_ID || "";
  const workflowId = process.env.GH_AW_WORKFLOW_ID || "";

  // Build the key-value pairs for the marker
  const parts = [];

  // Always include agentic-workflow name
  parts.push(`gh-aw-agentic-workflow: ${workflowName}`);

  // Add tracker-id if available (for searchability and tracing)
  if (trackerId) {
    parts.push(`gh-aw-tracker-id: ${trackerId}`);
  }

  // Add engine ID if available
  if (engineId) {
    parts.push(`engine: ${engineId}`);
  }

  // Add version if available
  if (engineVersion) {
    parts.push(`version: ${engineVersion}`);
  }

  // Add model if available
  if (engineModel) {
    parts.push(`model: ${engineModel}`);
  }

  // Add numeric run ID if available
  if (runId) {
    parts.push(`id: ${runId}`);
  }

  // Add workflow identifier if available
  if (workflowId) {
    parts.push(`workflow_id: ${workflowId}`);
  }

  // Always include run URL
  parts.push(`run: ${runUrl}`);

  // Return the XML comment marker
  return `<!-- ${parts.join(", ")} -->`;
}

/**
 * Get the detection caution alert for expired entity closing comments.
 * Reads GH_AW_DETECTION_CONCLUSION and GH_AW_DETECTION_REASON from environment variables.
 * Returns the caution alert markdown when conclusion is "warning", or empty string otherwise.
 *
 * Note: This function is intentionally kept inline (not imported from messages_footer.cjs)
 * because importing messages_footer.cjs here would cause the bundler to inline
 * messages_core.cjs which contains 'GH_AW_SAFE_OUTPUT_MESSAGES:' in a warning message,
 * breaking tests that check for env var declarations.
 *
 * The equivalent function in messages_footer.cjs is getDetectionCautionAlert().
 * If the caution alert format changes in either location, BOTH functions must be updated
 * together to keep them in sync.
 *
 * @param {string} workflowName - Name of the workflow
 * @param {string} runUrl - URL of the workflow run
 * @returns {string} Caution alert markdown or empty string
 */
function getExpiredEntityCautionAlert(workflowName, runUrl) {
  const detectionConclusion = process.env.GH_AW_DETECTION_CONCLUSION;
  if (detectionConclusion !== "warning") {
    return "";
  }
  const detectionReason = process.env.GH_AW_DETECTION_REASON || "";
  const reasonDescriptions = {
    threat_detected: "Potential security threats were detected in the agent output.",
    agent_failure: "The threat detection engine failed to produce results.",
    parse_error: "The threat detection results could not be parsed.",
  };
  const reasonText = reasonDescriptions[detectionReason] || "The threat detection analysis could not be completed.";
  return `> [!CAUTION]\n> **Security scanning requires review** for [${workflowName}](${runUrl})\n>\n> <details>\n> <summary>Details</summary>\n>\n> ${reasonText} The workflow output should be reviewed before merging.\n>\n> Review the [workflow run logs](${runUrl}) for details.\n> </details>`;
}

/**
 * Generate footer for expired entity closing comments.
 * Note: The detection caution alert is NOT included here; callers are responsible for
 * prepending it to the top of the full closing message using getExpiredEntityCautionAlert.
 * @param {string} workflowName - Name of the workflow
 * @param {string} runUrl - URL of the workflow run
 * @param {string} workflowId - Workflow identifier
 * @returns {string} Footer text with workflow run link and XML markers
 */
function generateExpiredEntityFooter(workflowName, runUrl, workflowId) {
  let footer = "";

  footer += `\n\n> Closed by [${workflowName}](${runUrl})`;

  // Add XML markers for searchability
  footer += "\n\n<!-- gh-aw-expired-comments -->";
  if (workflowId) {
    footer += "\n" + generateWorkflowIdMarker(workflowId);
  }
  footer += "\n" + generateXMLMarker(workflowName, runUrl);

  return footer;
}

/**
 * Generates a standalone workflow-call-id XML comment marker for close-older-issues
 * disambiguation. This marker contains the calling workflow's runtime identity
 * ("owner/repo/workflow-id") and is used to distinguish multiple callers that share
 * the same reusable workflow (and therefore the same `gh-aw-workflow-id`).
 *
 * @param {string} callerWorkflowId - Calling workflow identifier (e.g. "owner/repo/workflow-id")
 * @returns {string} Standalone workflow-call-id XML comment marker
 */
function generateWorkflowCallIdMarker(callerWorkflowId) {
  return `<!-- gh-aw-workflow-call-id: ${callerWorkflowId} -->`;
}

/**
 * Normalizes a user-supplied close-older-key to identifier style.
 * Converts to lowercase, replaces runs of non-alphanumeric/dash/underscore characters
 * with a single dash, then trims leading and trailing dashes and underscores.
 *
 * Examples: "My Key!" → "my-key", "  hello world  " → "hello-world"
 *
 * @param {string} key - Raw user-supplied key
 * @returns {string} Normalized identifier-style key, or empty string if nothing remains
 */
function normalizeCloseOlderKey(key) {
  return key
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_-]+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^[-_]+|[-_]+$/g, "");
}

/**
 * Generates a standalone close-key XML comment marker for close-older matching.
 * When a user provides an explicit `close-older-key`, this marker is embedded in
 * the issue/discussion body and used as the primary deduplication key instead of
 * the workflow-id or workflow-call-id markers.
 *
 * @param {string} closeKey - Normalized close-older deduplication key
 * @returns {string} Standalone close-key XML comment marker
 */
function generateCloseKeyMarker(closeKey) {
  return `<!-- gh-aw-close-key: ${closeKey} -->`;
}

/**
 * Gets the close-key marker content (without XML comment wrapper) for searching.
 * This is used when searching for issues/discussions by close-older-key.
 *
 * @param {string} closeKey - Normalized close-older deduplication key
 * @returns {string} Close-key marker content for search queries
 */
function getCloseKeyMarkerContent(closeKey) {
  return `gh-aw-close-key: ${closeKey}`;
}

/**
 * Validate that an extracted workflow ID has a safe, expected format.
 * Workflow IDs are file basenames (without .md) and must not contain
 * path traversal sequences or other shell-unsafe characters.
 *
 * @param {string} id - Candidate workflow ID
 * @returns {boolean} True if the ID is safe to use
 */
function isValidWorkflowId(id) {
  // Allow alphanumeric characters, hyphens, underscores, and dots.
  // Reject anything else, as well as path traversal sequences like "..".
  return id.length > 0 && id.length <= 100 && /^[\w.-]+$/.test(id) && !id.includes("..");
}

/**
 * Extract the workflow_id from an issue body using XML comment markers.
 *
 * Looks for (in priority order):
 * 1. Standalone marker: <!-- gh-aw-workflow-id: my-workflow -->
 * 2. Combined marker: <!-- gh-aw-agentic-workflow: ..., workflow_id: my-workflow, ... -->
 * 3. Workflow-call-id marker: <!-- gh-aw-workflow-call-id: owner/repo/my-workflow -->
 *    (extracts the last path segment to get the workflow ID)
 *
 * The combined and call-id markers are only searched within actual HTML comment blocks
 * to prevent unintended matches in user-provided content.
 *
 * Any `.yml`, `.yaml`, or `.lock.yml` extension in the extracted ID is stripped so the
 * result is always a bare workflow identifier (filename without extension).
 *
 * @param {string|null|undefined} body - Issue body
 * @returns {string|null} Workflow ID or null if not found or invalid
 */
function extractWorkflowId(body) {
  if (!body) return null;

  // Try standalone marker: <!-- gh-aw-workflow-id: my-workflow -->
  const standaloneMatch = body.match(/<!--\s*gh-aw-workflow-id:\s*([\w.-]+)\s*-->/);
  if (standaloneMatch) {
    const id = normalizeWorkflowId(standaloneMatch[1].trim());
    return isValidWorkflowId(id) ? id : null;
  }

  // Try combined marker, but only within HTML comment blocks that contain
  // gh-aw-agentic-workflow: to avoid matching user content.
  const commentMatch = body.match(/<!--\s*gh-aw-agentic-workflow:[^>]*?workflow_id:\s*([\w.-]+)[\s,>]/s);
  if (commentMatch) {
    const id = normalizeWorkflowId(commentMatch[1].trim());
    return isValidWorkflowId(id) ? id : null;
  }

  // Try workflow-call-id marker (handles workflow_dispatch): <!-- gh-aw-workflow-call-id: owner/repo/my-workflow -->
  // The call-id has the form "owner/repo/workflow-id"; extract the last non-empty path segment.
  const callIdMatch = body.match(/<!--\s*gh-aw-workflow-call-id:\s*([^\s>][^>]*?)\s*-->/);
  if (callIdMatch) {
    const segments = callIdMatch[1].trim().split("/");
    const raw = segments[segments.length - 1].trim();
    if (raw.length === 0) return null;
    const id = normalizeWorkflowId(raw);
    return isValidWorkflowId(id) ? id : null;
  }

  return null;
}

/**
 * Strip workflow file extension (.yml, .yaml, .lock.yml) from a workflow identifier.
 * This ensures we always work with the bare workflow ID (basename without extension).
 *
 * @param {string} id - Raw workflow identifier
 * @returns {string} Bare workflow identifier
 */
function normalizeWorkflowId(id) {
  return id.replace(/\.(lock\.yml|yml|yaml)$/i, "");
}

module.exports = {
  generateXMLMarker,
  generateWorkflowIdMarker,
  generateWorkflowCallIdMarker,
  getWorkflowIdMarkerContent,
  matchesWorkflowId,
  isValidWorkflowId,
  extractWorkflowId,
  normalizeWorkflowId,
  generateExpiredEntityFooter,
  getExpiredEntityCautionAlert,
  normalizeCloseOlderKey,
  generateCloseKeyMarker,
  getCloseKeyMarkerContent,
};
